import React from 'react';
import { FiPackage, FiTruck, FiBriefcase, FiMapPin, FiBox, FiGlobe } from 'react-icons/fi';

// 1. Service Card Component (Hyaat chuk honar nahi)
const ServiceCard = ({ icon: Icon, title, desc, color }) => (
  <div style={{
    flex: '1', minWidth: '280px', margin: '15px', padding: '30px',
    backgroundColor: 'rgba(255, 255, 255, 0.95)', borderRadius: '20px', textAlign: 'center',
    boxShadow: '0 10px 30px rgba(0,0,0,0.1)', borderTop: `6px solid ${color}`,
    backdropFilter: 'blur(10px)'
  }}>
    <div style={{ fontSize: '3rem', color: color, marginBottom: '15px' }}><Icon /></div>
    <h5 style={{ fontWeight: 'bold', color: '#333' }}>{title}</h5>
    <p style={{ color: '#666', fontSize: '0.85rem' }}>{desc}</p>
    <button style={{ backgroundColor: color, color: 'white', border: 'none', padding: '10px 25px', borderRadius: '25px', fontWeight: 'bold', cursor: 'pointer' }}>Select</button>
  </div>
);

// 2. Main App Component
function App() {
  const bgStyle = {
    backgroundImage: `linear-gradient(rgba(255,255,255,0.6), rgba(255,255,255,0.6)), url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?q=80&w=2000')`,
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    backgroundAttachment: 'fixed',
    minHeight: '100vh',
    fontFamily: 'Arial, sans-serif'
  };

  return (
    <div style={bgStyle}>
      {/* Navbar */}
      <nav style={{ backgroundColor: '#0056b3', padding: '15px 50px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', boxShadow: '0 4px 10px rgba(0,0,0,0.2)' }}>
        <h2 style={{ color: 'white', fontWeight: '800', margin: 0 }}>APNI MANZIL</h2>
        <div style={{ backgroundColor: '#28a745', color: 'white', padding: '10px 25px', borderRadius: '30px', fontWeight: 'bold', cursor: 'pointer' }}>Login</div>
      </nav>

      {/* Hero Section */}
      <div style={{ textAlign: 'center', padding: '60px 20px' }}>
        <h1 style={{ fontSize: '3.2rem', fontWeight: '900', color: '#1a1a1a', marginBottom: '10px' }}>Logistics Aggregator</h1>
        <h4 style={{ color: '#0056b3', fontWeight: 'bold', background: 'white', display: 'inline-block', padding: '8px 25px', borderRadius: '40px', boxShadow: '0 4px 10px rgba(0,0,0,0.1)' }}>
          One Solution for All Deliveries
        </h4>
      </div>

      {/* Services Grid */}
      <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center', maxWidth: '1200px', margin: '0 auto', paddingBottom: '50px' }}>
        <ServiceCard icon={FiPackage} title="Courier Services" desc="Express Domestic & Local Delivery" color="#2ecc71" />
        <ServiceCard icon={FiTruck} title="Transport" desc="Heavy Haulage & Trucking" color="#f1c40f" />
        <ServiceCard icon={FiBox} title="Packers & Movers" desc="Safe Home & Office Moving" color="#f39c12" />
        <ServiceCard icon={FiBriefcase} title="Business MSME" desc="Bulk 3PL & Supply Chain" color="#3498db" />
      </div>
    </div>
  );
}

export default App;
